package main

import (
	"bytes"
	"fmt"
	"io"
	"net/http"
	"net/url"
	"strings"
	"time"

	"github.com/labstack/echo/v4"
	"golang.org/x/net/html"
)

// Request body
type PreviewRequest struct {
	URL string `json:"url"`
}

// Response body
type PreviewResponse struct {
	Title       string `json:"title,omitempty"`
	Description string `json:"description,omitempty"`
}

func FetchURLPreview(ctx echo.Context) error {
	req := new(PreviewRequest)
	if err := ctx.Bind(req); err!= nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid JSON"})
	}

	// Validate URL
	parsedURL, err := url.Parse(req.URL)
	if err!= nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid URL format"})
	}

	if parsedURL.Scheme!= "http" && parsedURL.Scheme!= "https" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Only HTTP/HTTPS URLs are allowed"})
	}

	// Fetch the URL with context support and timeout
	client := &http.Client{Timeout: 3 * time.Second}
	httpReq, err := http.NewRequestWithContext(ctx.Request().Context(), http.MethodGet, parsedURL.String(), nil)
	if err!= nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to create request"})
	}
	httpReq.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreviewBot/1.0)")

	resp, err := client.Do(httpReq)
	if err!= nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to fetch URL"})
	}
	defer resp.Body.Close()

	if resp.StatusCode!= http.StatusOK {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": fmt.Sprintf("HTTP %d", resp.StatusCode)})
	}

	// Read up to 10MB to avoid processing excessively large responses
	body, err := io.ReadAll(io.LimitReader(resp.Body, 10<<20))
	if err!= nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to read response body"})
	}

	title, description := extractTitleAndDescription(body)

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

func extractTitleAndDescription(htmlContent []byte) (string, string) {
	var title, description string
	tokenizer := html.NewTokenizer(bytes.NewReader(htmlContent))
	inTitle := false

	for {
		tokenType := tokenizer.Next()
		switch tokenType {
		case html.ErrorToken:
			// End of input or error, return collected values
			return strings.TrimSpace(title), strings.TrimSpace(description)
		case html.StartTagToken, html.SelfClosingTagToken:
			tagName, hasAttr := tokenizer.TagName()
			tagNameStr := string(tagName)
			if strings.EqualFold(tagNameStr, "title") {
				inTitle = true
			} else if strings.EqualFold(tagNameStr, "meta") {
				if hasAttr {
					var nameAttr, contentAttr string
					for {
						attrKey, attrVal, moreAttr := tokenizer.TagAttr()
						keyStr := string(attrKey)
						valStr := string(attrVal)
						if strings.EqualFold(keyStr, "name") {
							nameAttr = valStr
						} else if strings.EqualFold(keyStr, "content") {
							contentAttr = valStr
						}
						if!moreAttr {
							break
						}
					}
					if strings.EqualFold(nameAttr, "description") {
						description = contentAttr
					}
				}
			}
		case html.TextToken:
			if inTitle {
				title += string(tokenizer.Text())
			}
		case html.EndTagToken:
			tagName, _ := tokenizer.TagName()
			tagNameStr := string(tagName)
			if strings.EqualFold(tagNameStr, "title") {
				inTitle = false
			}
			// Early exit after head section, as relevant tags are here
			if strings.EqualFold(tagNameStr, "head") {
				return strings.TrimSpace(title), strings.TrimSpace(description)
			}
		}

		// Early exit once both required fields are found
		if title!= "" && description!= "" {
			break
		}
	}

	return strings.TrimSpace(title), strings.TrimSpace(description)
}

func main() {
	e := echo.New()
	e.POST("/preview", FetchURLPreview)
	// Start server on port 8080
	e.Logger.Fatal(e.Start(":8080"))
}

