package main

import (
	"bytes"
	"errors"
	"fmt"
	"io"
	"net"
	"net/http"
	"net/url"
	"strings"
	"time"

	"github.com/labstack/echo/v4"
	"golang.org/x/net/html"
)

// Request body
type PreviewRequest struct {
	URL string `json:"url"`
}

// Response body
type PreviewResponse struct {
	Title       string `json:"title,omitempty"`
	Description string `json:"description,omitempty"`
}

const (
	maxBodySize   = 1 << 20 // 1MB maximum response size to prevent DoS
	maxRedirects  = 10       // Maximum number of redirects to follow
	requestTimeout = 3 * time.Second // Timeout for HTTP requests
)

// isPrivateIP checks if an IP address is in a private/loopback range
func isPrivateIP(ip net.IP) bool {
	if ip.IsLoopback() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
		return true
	}

	// IPv4 private ranges
	privateIPv4s := []*net.IPNet{
		{IP: net.ParseIP("10.0.0.0"), Mask: net.CIDRMask(8, 32)},
		{IP: net.ParseIP("172.16.0.0"), Mask: net.CIDRMask(12, 32)},
		{IP: net.ParseIP("192.168.0.0"), Mask: net.CIDRMask(16, 32)},
	}
	for _, priv := range privateIPv4s {
		if priv.Contains(ip) {
			return true
		}
	}

	// IPv6 ULA range (fd00::/8)
	privateIPv6 := &net.IPNet{IP: net.ParseIP("fd00::"), Mask: net.CIDRMask(8, 128)}
	return privateIPv6.Contains(ip)
}

// validateURLHost checks if the URL host resolves to public IPs only (prevents SSRF)
func validateURLHost(parsedURL *url.URL) error {
	host := parsedURL.Hostname()
	ips, err := net.LookupIP(host)
	if err != nil {
		return fmt.Errorf("failed to resolve host: %w", err)
	}

	for _, ip := range ips {
		if isPrivateIP(ip) {
			return fmt.Errorf("access to private/loopback IP addresses is not allowed: %s", ip.String())
		}
	}
	return nil
}

// extractTitleAndDescription parses HTML to extract page title and meta description
func extractTitleAndDescription(htmlContent []byte) (string, string) {
	doc, err := html.Parse(bytes.NewReader(htmlContent))
	if err != nil {
		return "", ""
	}

	var title string
	var description string

	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		// Early exit if we have both required fields
		if title != "" && description != "" {
			return
		}

		if n.Type == html.ElementNode {
			switch n.Data {
			case "title":
				// Collect all text content from the title tag
				var titleText strings.Builder
				for c := n.FirstChild; c != nil; c = c.NextSibling {
					if c.Type == html.TextNode {
						titleText.WriteString(c.Data)
					}
				}
				title = strings.TrimSpace(titleText.String())

			case "meta":
				// Check for description meta tag
				nameAttr := ""
				contentAttr := ""
				for _, attr := range n.Attr {
					switch strings.ToLower(attr.Key) {
					case "name":
						nameAttr = strings.ToLower(attr.Val)
					case "content":
						contentAttr = attr.Val
					}
				}
				if nameAttr == "description" {
					description = strings.TrimSpace(contentAttr)
				}

			case "body":
				// Stop traversing once we reach the body (meta/title are in head)
				return
			}
		}

		// Traverse child nodes
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}

	traverse(doc)
	return title, description
}

func FetchURLPreview(ctx echo.Context) error {
	req := new(PreviewRequest)
	if err := ctx.Bind(req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid JSON"})
	}

	// Validate URL format and scheme
	parsedURL, err := url.Parse(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid URL format"})
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Only HTTP/HTTPS URLs are allowed"})
	}

	// Validate host to prevent SSRF
	if err := validateURLHost(parsedURL); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": err.Error()})
	}

	// Create HTTP client with safe redirect handling and timeout
	client := &http.Client{
		Timeout: requestTimeout,
		CheckRedirect: func(req *http.Request, via []*http.Request) error {
			// Validate redirect URLs
			if err := validateURLHost(req.URL); err != nil {
				return err
			}
			// Enforce redirect limit
			if len(via) >= maxRedirects {
				return errors.New("too many redirects")
			}
			return nil
		},
	}

	// Create request with context from the Echo context (supports cancellation)
	httpReq, err := http.NewRequestWithContext(ctx.Request().Context(), http.MethodGet, parsedURL.String(), nil)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to create request"})
	}
	httpReq.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreviewBot/1.0)")

	// Execute the request
	resp, err := client.Do(httpReq)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to fetch URL"})
	}
	defer resp.Body.Close()

	// Check for successful response
	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": fmt.Sprintf("URL returned HTTP status %d", resp.StatusCode)})
	}

	// Read limited response body to prevent DoS attacks
	body, err := io.ReadAll(io.LimitReader(resp.Body, maxBodySize))
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to read response body"})
	}

	// Extract title and description from HTML
	title, description := extractTitleAndDescription(body)

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

func main() {
	e := echo.New()
	e.POST("/preview", FetchURLPreview)
	e.Start(":8080")
}

