import (
	"io"
	"net/http"
	"time"

	"github.com/labstack/echo/v4"
	"golang.org/x/net/html"
)

// PreviewRequest represents the incoming JSON request body
type PreviewRequest struct {
	URL string `json:"url"`
}

// PreviewResponse represents the outgoing JSON response
type PreviewResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
}

// getTextContent extracts all text content from an HTML node and its children
func getTextContent(n *html.Node) string {
	var text string
	var f func(*html.Node)
	f = func(n *html.Node) {
		if n.Type == html.TextNode {
			text += n.Data
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			f(c)
		}
	}
	f(n)
	return text
}

// extractMetadata parses HTML to extract page title and meta description
func extractMetadata(r io.Reader) (string, string, error) {
	doc, err := html.Parse(r)
	if err != nil {
		return "", "", err
	}

	var title, description string
	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if n.Type == html.ElementNode {
			switch n.Data {
			case "title":
				title = getTextContent(n)
			case "meta":
				var name, content string
				for _, attr := range n.Attr {
					switch attr.Key {
					case "name":
						name = attr.Val
					case "content":
						content = attr.Val
					}
				}
				if name == "description" {
					description = content
				}
			}
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}
	traverse(doc)
	return title, description, nil
}

// FetchURLPreview handles POST requests to /preview to fetch and parse URL metadata
func FetchURLPreview(ctx echo.Context) error {
	var req PreviewRequest
	if err := ctx.Bind(&req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{
			"error": "invalid request body",
		})
	}

	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{
			"error": "url field is required",
		})
	}

	// Create HTTP client with 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Create HTTP request with context and user agent
	httpReq, err := http.NewRequestWithContext(ctx.Request().Context(), "GET", req.URL, nil)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{
			"error": "failed to create HTTP request: " + err.Error(),
		})
	}
	httpReq.Header.Set("User-Agent", "URL-Preview-Fetcher/1.0 (+https://example.com)")

	// Execute the request
	resp, err := client.Do(httpReq)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{
			"error": "failed to fetch URL: " + err.Error(),
		})
	}
	defer resp.Body.Close()

	// Extract metadata from HTML
	title, description, err := extractMetadata(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{
			"error": "failed to parse HTML: " + err.Error(),
		})
	}

	// Return the response
	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

