func isRestrictedIP(ip net.IP) bool {
	if ip == nil {
		return true
	}

	// Check IPv4 ranges
	if ip4 := ip.To4(); ip4!= nil {
		// Loopback (127.0.0.0/8)
		if ip4[0] == 127 {
			return true
		}
		// Private network 10.0.0.0/8
		if ip4[0] == 10 {
			return true
		}
		// Private network 172.16.0.0/12
		if ip4[0] == 172 && ip4[1] >= 16 && ip4[1] <= 31 {
			return true
		}
		// Private network 192.168.0.0/16
		if ip4[0] == 192 && ip4[1] == 168 {
			return true
		}
		// Link-local (169.254.0.0/16)
		if ip4[0] == 169 && ip4[1] == 254 {
			return true
		}
		return false
	}

	// Check IPv6 ranges
	if ip.IsLoopback() {
		return true
	}
	if ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
		return true
	}
	// Unique local address (fc00::/7)
	if len(ip) >= 1 && (ip[0]&0xfe) == 0xfc {
		return true
	}

	return false
}

func customDialContext(ld *net.Dialer, ctx context.Context, network, addr string) (net.Conn, error) {
	host, port, err := net.SplitHostPort(addr)
	if err!= nil {
		return nil, fmt.Errorf("invalid address: %w", err)
	}

	ips, err := net.DefaultResolver.LookupIP(ctx, "ip", host)
	if err!= nil {
		return nil, fmt.Errorf("failed to resolve host: %w", err)
	}

	var lastErr error
	for _, ip := range ips {
		if isRestrictedIP(ip) {
			continue
		}
		dialAddr := net.JoinHostPort(ip.String(), port)
		conn, err := ld.DialContext(ctx, network, dialAddr)
		if err == nil {
			return conn, nil
		}
		lastErr = err
	}

	if lastErr!= nil {
		return nil, fmt.Errorf("failed to dial allowed IPs: %w", lastErr)
	}
	return nil, errors.New("no allowed IP addresses found for host")
}

func FetchURLPreview(ctx echo.Context) error {
	previewReq := new(PreviewRequest)
	if err := ctx.Bind(previewReq); err!= nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid JSON"})
	}

	// Validate URL format and scheme
	parsedURL, err := url.Parse(previewReq.URL)
	if err!= nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid URL format"})
	}

	if parsedURL.Scheme!= "http" && parsedURL.Scheme!= "https" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Only HTTP/HTTPS URLs are allowed"})
	}

	// Set up HTTP client with SSRF protection
	dialer := &net.Dialer{
		Timeout:   5 * time.Second,
		KeepAlive: 30 * time.Second,
	}

	transport := &http.Transport{
		DialContext: func(ctx context.Context, network, addr string) (net.Conn, error) {
			return customDialContext(dialer, ctx, network, addr)
		},
		TLSHandshakeTimeout: 5 * time.Second,
		IdleConnTimeout:     30 * time.Second,
	}

	client := &http.Client{
		Timeout:   15 * time.Second,
		Transport: transport,
		CheckRedirect: func(req *http.Request, via []*http.Request) error {
			if len(via) >= 5 {
				return errors.New("too many redirects")
			}
			// Ensure redirect URLs also use HTTP/HTTPS
			if req.URL.Scheme!= "http" && req.URL.Scheme!= "https" {
				return errors.New("redirect to invalid scheme")
			}
			return nil
		},
	}

	// Create HTTP request with context from echo
	httpReq, err := http.NewRequestWithContext(ctx.Request().Context(), http.MethodGet, previewReq.URL, nil)
	if err!= nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to create request"})
	}
	httpReq.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreviewBot/1.0)")

	resp, err := client.Do(httpReq)
	if err!= nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Failed to fetch URL"})
	}
	defer resp.Body.Close()

	// Check if status is OK
	if resp.StatusCode!= http.StatusOK {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": fmt.Sprintf("HTTP error: %d", resp.StatusCode)})
	}

	// Limit response body to 1MB to prevent memory exhaustion
	body, err := io.ReadAll(io.LimitReader(resp.Body, 1<<20))
	if err!= nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to read response"})
	}

	title, description := extractTitleAndDescription(body)

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

func extractTitleAndDescription(htmlContent []byte) (string, string) {
	var title, description string

	doc, err := html.Parse(bytes.NewReader(htmlContent))
	if err!= nil {
		return title, description
	}

	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if n.Type == html.ElementNode {
			switch strings.ToLower(n.Data) {
			case "title":
				// Collect text from all title children
				var titleText strings.Builder
				for c := n.FirstChild; c!= nil; c = c.NextSibling {
					if c.Type == html.TextNode {
						titleText.WriteString(c.Data)
					}
				}
				title = strings.TrimSpace(titleText.String())
			case "meta":
				name := ""
				content := ""
				for _, attr := range n.Attr {
					switch strings.ToLower(attr.Key) {
					case "name":
						name = strings.ToLower(attr.Val)
					case "content":
						content = attr.Val
					}
				}
				if name == "description" {
					description = strings.TrimSpace(content)
				}
			}
		}
		// Early exit if we have both required fields
		if title!= "" && description!= "" {
			return
		}
		for c := n.FirstChild; c!= nil; c = c.NextSibling {
			traverse(c)
			if title!= "" && description!= "" {
				return
			}
		}
	}

	traverse(doc)
	return title, description
}

