package main

import (
	"net/http"
	"strings"
	"time"

	"github.com/labstack/echo/v4"
	"golang.org/x/net/html"
)

type PreviewRequest struct {
	URL string `json:"url"`
}

type PreviewResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
}

func FetchURLPreview(ctx echo.Context) error {
	var req PreviewRequest
	if err := ctx.Bind(&req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "invalid request body"})
	}

	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "url is required"})
	}

	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	resp, err := client.Get(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "failed to fetch url"})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "url returned non-200 status"})
	}

	tokenizer := html.NewTokenizer(resp.Body)
	var title string
	var description string
	inTitle := false

	for {
		tokenType := tokenizer.Next()
		switch tokenType {
		case html.ErrorToken:
			goto endParse
		case html.StartTagToken:
			token := tokenizer.Token()
			if token.Data == "title" {
				inTitle = true
			} else if token.Data == "meta" {
				var name, content string
				for _, attr := range token.Attr {
					if attr.Key == "name" {
						name = attr.Val
					} else if attr.Key == "content" {
						content = attr.Val
					}
				}
				if strings.EqualFold(name, "description") {
					description = content
				}
			}
		case html.TextToken:
			if inTitle {
				title = strings.TrimSpace(string(tokenizer.Text()))
			}
		case html.EndTagToken:
			token := tokenizer.Token()
			if token.Data == "title" {
				inTitle = false
			}
		}
	}
endParse:

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

func main() {
	e := echo.New()
	e.POST("/preview", FetchURLPreview)
	e.Logger.Fatal(e.Start(":8080"))
}

