		{IP: net.ParseIP("192.168.0.0"), Mask: net.CIDRMask(16, 32)},
		// Link-local
		{IP: net.ParseIP("169.254.0.0"), Mask: net.CIDRMask(16, 32)},
	}
	blockedIPv6Networks = []*net.IPNet{
		// IPv6 loopback
		{IP: net.ParseIP("::1"), Mask: net.CIDRMask(128, 128)},
		// IPv6 unique local address
