func isIPBlocked(ip net.IP) bool {
	if ip == nil {
		return true
	}
	if ip.To4() != nil {
		for _, network := range blockedIPv4Networks {
			if network.Contains(ip) {
				return true
			}
		}
	} else {
		for _, network := range blockedIPv6Networks {
			if network.Contains(ip) {
				return true
			}
		}
	}
	// Block multicast addresses as well
	return ip.IsMulticast()
}

func FetchURLPreview(ctx echo.Context) error {
	req := new(PreviewRequest)
	if err := ctx.Bind(req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid JSON"})
	}

	// Validate URL format
	parsedURL, err := url.Parse(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid URL format"})
	}

	// Ensure scheme is HTTP/HTTPS
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Only HTTP/HTTPS URLs are allowed"})
	}

	// Ensure host is not empty
	if parsedURL.Host == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "URL must have a valid host"})
