	resp, err := client.Do(httpReq)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Failed to fetch URL"})
	}
	defer resp.Body.Close()

	// Check for successful status code
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": fmt.Sprintf("URL returned non-success status code: %d", resp.StatusCode)})
	}

