package main

import (
	"fmt"
	"log"
	"net/http"
	"net/url"
	"strings"
	"time"

	"github.com/labstack/echo/v4"
	"golang.org/x/net/html"
)

// PreviewRequest represents the incoming JSON request body
type PreviewRequest struct {
	URL string `json:"url"`
}

// PreviewResponse represents the outgoing JSON response
type PreviewResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
}

// getText extracts all text content from an HTML node and its descendants, trimmed of whitespace
func getText(n *html.Node) string {
	var buf strings.Builder
	var visit func(*html.Node)
	visit = func(node *html.Node) {
		if node.Type == html.TextNode {
			buf.WriteString(node.Data)
		}
		for c := node.FirstChild; c != nil; c = c.NextSibling {
			visit(c)
		}
	}
	visit(n)
	return strings.TrimSpace(buf.String())
}

// extractMetadata traverses an HTML node tree to find the page title and meta description
func extractMetadata(n *html.Node) (title, description string) {
	if n.Type == html.ElementNode {
		switch n.Data {
		case "title":
			title = getText(n)
		case "meta":
			var nameAttr, contentAttr string
			for _, attr := range n.Attr {
				if strings.EqualFold(attr.Key, "name") {
					nameAttr = attr.Val
				} else if strings.EqualFold(attr.Key, "content") {
					contentAttr = attr.Val
				}
			}
			if strings.EqualFold(nameAttr, "description") {
				description = strings.TrimSpace(contentAttr)
			}
		}
	}

	// Traverse children only if we haven't found both metadata fields
	for c := n.FirstChild; c != nil; c = c.NextSibling {
		if title == "" || description == "" {
			childTitle, childDesc := extractMetadata(c)
			if title == "" {
				title = childTitle
			}
			if description == "" {
				description = childDesc
			}
		}
	}

	return title, description
}

// FetchURLPreview handles POST requests to /preview to generate a URL preview
func FetchURLPreview(ctx echo.Context) error {
	// Bind incoming JSON request
	var req PreviewRequest
	if err := ctx.Bind(&req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{
			"error": fmt.Sprintf("invalid request body: %v", err),
		})
	}

	// Validate URL is present
	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{
			"error": "url field is required",
		})
	}

	// Parse and validate URL format
	parsedURL, err := url.ParseRequestURI(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{
			"error": fmt.Sprintf("invalid URL format: %v", err),
		})
	}

	// Ensure URL uses HTTP/HTTPS scheme
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{
			"error": "URL must use http or https scheme",
		})
	}

	// Create HTTP client with 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Fetch the URL content
	resp, err := client.Get(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{
			"error": fmt.Sprintf("failed to fetch URL: %v", err),
		})
	}
	defer resp.Body.Close()

	// Check for successful response status
	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusBadRequest, map[string]string{
			"error": fmt.Sprintf("URL returned non-success status code: %d", resp.StatusCode),
		})
	}

	// Parse HTML content
	doc, err := html.Parse(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{
			"error": fmt.Sprintf("failed to parse HTML content: %v", err),
		})
	}

	// Extract title and description
	title, description := extractMetadata(doc)

	// Return successful response
	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

func main() {
	// Initialize Echo instance
	e := echo.New()

	// Register the preview endpoint
	e.POST("/preview", FetchURLPreview)

	// Start server on port 8080
	log.Println("Starting server on :8080")
	if err := e.Start(":8080"); err != nil && err != http.ErrServerClosed {
		log.Fatalf("Server failed to start: %v", err)
	}
}

