	}
	title, description := extractTitleAndDescription(body)
	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

func extractTitleAndDescription(htmlContent []byte) (string, string) {
	var title, description string
	tokenizer := html.NewTokenizer(bytes.NewReader(htmlContent))
	for {
		tt := tokenizer.Next()
		switch tt {
		case html.ErrorToken:
			return title, description
		case html.StartTagToken:
			tagName, hasAttr := tokenizer.TagName()
			switch string(tagName) {
			case "title":
				if tokenizer.Next() == html.TextToken {
					title = strings.TrimSpace(string(tokenizer.Text()))
				}
			case "meta":
				var name, content string
				for hasAttr {
					attrKey, attrVal, moreAttr := tokenizer.TagAttr()
					key := strings.ToLower(string(attrKey))
					switch key {
					case "name":
						name = strings.ToLower(string(attrVal))
					case "content":
						content = string(attrVal)
					}
					hasAttr = moreAttr
				}
				if name == "description" && content!= "" {
					description = content
				}
			case "body":
				return title, description
			}
		case html.EndTagToken:
			tagName, _ := tokenizer.TagName()
			if string(tagName) == "head" {
				return title, description
			}
		}
		if title!= "" && description!= "" {
			break
		}
	}
	return title, description
}

