	"strings"
	"time"

	"github.com/labstack/echo/v4"
	"golang.org/x/net/html"
)

// Request body
type PreviewRequest struct {
	URL string `json:"url"`
}

// Response body
type PreviewResponse struct {
	Title       string `json:"title,omitempty"`
	Description string `json:"description,omitempty"`
}

// stripBrackets removes brackets from IPv6 literal hosts
func stripBrackets(host string) string {
	if strings.HasPrefix(host, "[") && strings.HasSuffix(host, "]") {
		return host[1 : len(host)-1]
	}
	return host
}

// isIPAllowed checks if an IP address is allowed (not private, loopback, etc.)
func isIPAllowed(ip net.IP) bool {
	if ip == nil {
		return false
	}
	// Block unspecified addresses (0.0.0.0, ::)
	if ip.IsUnspecified() {
		return false
	}
	// Block loopback addresses
	if ip.IsLoopback() {
		return false
	}
	// Block link-local addresses
	if ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
		return false
	}
	// Block multicast addresses
	if ip.IsMulticast() {
		return false
	}
	// Block private IPv4 ranges
	privateIPv4s := []*net.IPNet{
		{IP: net.ParseIP("10.0.0.0"), Mask: net.CIDRMask(8, 32)},
		{IP: net.ParseIP("172.16.0.0"), Mask: net.CIDRMask(12, 32)},
		{IP: net.ParseIP("192.168.0.0"), Mask: net.CIDRMask(16, 32)},
	}
	for _, r := range privateIPv4s {
		if r.Contains(ip) {
			return false
		}
	}
	// Block IPv6 ULA (fc00::/7)
	ulaIPv6 := &net.IPNet{IP: net.ParseIP("fc00::"), Mask: net.CIDRMask(7, 128)}
	if ulaIPv6.Contains(ip) {
		return false
	}
	return true
}

// validateURL checks if the URL is safe to fetch
func validateURL(u *url.URL) error {
	if u.Scheme!= "http" && u.Scheme!= "https" {
		return fmt.Errorf("only HTTP/HTTPS URLs are allowed")
	}
	if u.Host == "" {
		return fmt.Errorf("URL must have a valid host")
	}

	// Extract host without port or brackets
	host, _, err := net.SplitHostPort(u.Host)
	if err!= nil {
		// No port, use host as-is
		host = u.Host
	}
	host = stripBrackets(host)

	// Resolve host and check IPs
	ips, err := net.LookupIP(host)
	if err!= nil {
		return fmt.Errorf("failed to resolve host")
	}
	// Check if at least one IP is allowed
	hasAllowedIP := false
	for _, ip := range ips {
		if isIPAllowed(ip) {
			hasAllowedIP = true
			break
		}
	}
	if!hasAllowedIP {
		return fmt.Errorf("URL resolves to a restricted address")
	}
	return nil
}

// safeDialContext is a custom dialer that checks IP addresses before connecting
func safeDialContext(ctx context.Context, network, addr string) (net.Conn, error) {
	// Extract host and port from address
	host, port, err := net.SplitHostPort(addr)
	if err!= nil {
		// If no port, use addr as host and empty port
		host = addr
		port = ""
	}
	host = stripBrackets(host)

	// Resolve host to IP addresses
	ips, err := net.LookupIP(host)
	if err!= nil {
		return nil, fmt.Errorf("failed to resolve host: %w", err)
	}

	// Find the first allowed IP address
	var allowedIP net.IP
	for _, ip := range ips {
		if isIPAllowed(ip) {
			allowedIP = ip
			break
		}
	}
	if allowedIP == nil {
		return nil, fmt.Errorf("no allowed IP addresses for host")
	}

	// Construct the dial address using the allowed IP and original port
	// net.JoinHostPort automatically handles IPv6 brackets
	dialAddr := net.JoinHostPort(allowedIP.String(), port)

	// Use standard dialer to connect
	dialer := &net.Dialer{
		Timeout: 2 * time.Second,
	}
	return dialer.DialContext(ctx, network, dialAddr)
}

func FetchURLPreview(ctx echo.Context) error {
	req := new(PreviewRequest)
	if err := ctx.Bind(req); err!= nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid JSON"})
	}

	// Validate URL format
