	if err!= nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid URL format"})
	}

	// Perform full URL validation (scheme, host, IP checks)
	if err := validateURL(parsedURL); err!= nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": err.Error()})
	}

	// Configure safe HTTP client
	client := &http.Client{
		Timeout: 5 * time.Second,
		CheckRedirect: func(req *http.Request, via []*http.Request) error {
			// Limit number of redirects
			if len(via) >= 5 {
				return http.ErrUseLastResponse
			}
			// Validate each redirect URL
			if err := validateURL(req.URL); err!= nil {
				return err
			}
			// Preserve user-agent header
			req.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreviewBot/1.0)")
			return nil
		},
		Transport: &http.Transport{
			DialContext:           safeDialContext,
			MaxIdleConns:          10,
			IdleConnTimeout:       30 * time.Second,
			TLSHandshakeTimeout:   2 * time.Second,
			ResponseHeaderTimeout: 2 * time.Second,
		},
	}

	// Create request with context from echo (supports cancellation)
	httpReq, err := http.NewRequestWithContext(ctx.Request().Context(), http.MethodGet, parsedURL.String(), nil)
	if err!= nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to create request"})
	}
	httpReq.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreviewBot/1.0)")

	// Fetch the URL
	resp, err := client.Do(httpReq)
	if err!= nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to fetch URL"})
	}
	defer resp.Body.Close()

	// Check for successful status code
	if resp.StatusCode!= http.StatusOK {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": fmt.Sprintf("URL returned status %d", resp.StatusCode)})
	}

