	body, err := io.ReadAll(io.LimitReader(resp.Body, 1<<20))
	if err!= nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to read response"})
	}

	// Extract title and description
	title, description := extractTitleAndDescription(body)

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

// extractTitleAndDescription parses HTML to extract page title and meta description
func extractTitleAndDescription(htmlContent []byte) (string, string) {
	var title string
	var description string
	tokenizer := html.NewTokenizer(strings.NewReader(string(htmlContent)))
	inTitle := false

	for {
		tokenType := tokenizer.Next()
		switch tokenType {
		case html.ErrorToken:
			// End of document or error, return what we have
			title = strings.TrimSpace(title)
			return title, description
		case html.StartTagToken, html.SelfClosingTagToken:
			tagName, hasAttr := tokenizer.TagName()
			tag := strings.ToLower(string(tagName))

			if tag == "title" {
				inTitle = true
			} else if tag == "meta" {
				var nameAttr string
				var contentAttr string
				for hasAttr {
					attrName, attrVal, moreAttr := tokenizer.TagAttr()
					attr := strings.ToLower(string(attrName))
					if attr == "name" {
						nameAttr = strings.ToLower(string(attrVal))
					} else if attr == "content" {
						contentAttr = string(attrVal)
					}
					hasAttr = moreAttr
				}
				if nameAttr == "description" && contentAttr!= "" {
					description = contentAttr
				}
			}
		case html.EndTagToken:
			tagName, _ := tokenizer.TagName()
			if strings.ToLower(string(tagName)) == "title" {
				inTitle = false
			}
		case html.TextToken:
			if inTitle {
				title += string(tokenizer.Text())
			}
		}

		// Early exit if we have both title and description
		if strings.TrimSpace(title)!= "" && description!= "" {
			break
		}
	}

	title = strings.TrimSpace(title)
	return title, description
}

