// FetchURLPreview handles POST /preview requests to generate URL previews
func FetchURLPreview(ctx echo.Context) error {
	// Bind incoming JSON request
	var req PreviewRequest
	if err := ctx.Bind(&req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{
			"error": "Invalid request body: please provide a JSON with 'url' field",
		})
	}

	// Validate URL presence
	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{
			"error": "URL field is required",
		})
	}

	// Validate URL format and scheme
	parsedURL, err := url.Parse(req.URL)
	if err!= nil || (parsedURL.Scheme!= "http" && parsedURL.Scheme!= "https") {
		return ctx.JSON(http.StatusBadRequest, map[string]string{
			"error": "Invalid URL: must be a valid HTTP/HTTPS URL",
		})
	}

	// Create HTTP client with 3-second timeout as required
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Create HTTP request with parent context from echo
	httpReq, err := http.NewRequestWithContext(ctx.Request().Context(), http.MethodGet, req.URL, nil)
	if err!= nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{
			"error": "Failed to prepare request",
		})
	}

	// Set a realistic User-Agent to avoid being blocked by default
	httpReq.Header.Set("User-Agent", "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/128.0.0.0 Safari/537.36 URLPreviewBot/1.0")

	// Execute the request
	resp, err := client.Do(httpReq)
	if err!= nil {
		// Handle timeout specifically
		if strings.Contains(err.Error(), "context deadline exceeded") || strings.Contains(err.Error(), "Client.Timeout") {
			return ctx.JSON(http.StatusGatewayTimeout, map[string]string{
				"error": "Request to fetch URL timed out after 3 seconds",
			})
		}
		return ctx.JSON(http.StatusBadRequest, map[string]string{
			"error": "Failed to fetch URL: " + err.Error(),
		})
	}
	defer resp.Body.Close()

	// Check for successful HTTP status
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.JSON(http.StatusBadGateway, map[string]string{
			"error": "URL returned non-success status: " + resp.Status,
		})
	}

	// Verify content type is HTML
	contentType := resp.Header.Get("Content-Type")
	if!strings.HasPrefix(strings.ToLower(contentType), "text/html") {
		return ctx.JSON(http.StatusUnsupportedMediaType, map[string]string{
			"error": "URL does not return HTML content (Content-Type: " + contentType + ")",
		})
	}

	// Parse HTML with goquery
	doc, err := goquery.NewDocumentFromReader(resp.Body)
	if err!= nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{
			"error": "Failed to parse HTML content",
		})
	}

	// Extract and clean title and description
	title := strings.TrimSpace(doc.Find("title").First().Text())
	description := strings.TrimSpace(doc.Find("meta[name='description']").AttrOr("content", ""))

	// Return successful response
	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

func main() {
	// Initialize Echo instance
	e := echo.New()

	// Register the preview handler
	e.POST("/preview", FetchURLPreview)

	// Start server on port 8080
	e.Logger.Fatal(e.Start(":8080"))
}

