	resp, err := client.Do(httpReq)
	if err != nil {
		if errors.Is(err, context.DeadlineExceeded) {
			return ctx.JSON(http.StatusRequestTimeout, map[string]string{"error": "request to url timed out after 3 seconds"})
		}
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": fmt.Sprintf("failed to fetch url: %v", err)})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": fmt.Sprintf("url returned status code %d", resp.StatusCode)})
	}

	contentType := resp.Header.Get("Content-Type")
	if !strings.Contains(strings.ToLower(contentType), "text/html") {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "url does not return html content"})
	}

	title, desc, err := extractMeta(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "failed to parse html content"})
	}

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: desc,
	})
}

func main() {
	e := echo.New()
	e.POST("/preview", FetchURLPreview)
	e.Logger.Fatal(e.Start(":8080"))
}

