	for _, ip := range ips {
		if isDisallowedIP(ip) {
			return nil, fmt.Errorf("disallowed IP: %s", ip.String())
		}
	}

	// Restrict to allowed ports
	allowedPorts := map[string]bool{
		"80":   true,
		"443":  true,
		"8080": true,
		"8443": true,
	}
	if !allowedPorts[port] {
		return nil, fmt.Errorf("disallowed port: %s", port)
	}

	// Proceed with dialing
	dialer := &net.Dialer{}
	return dialer.DialContext(ctx, network, addr)
}

func FetchURLPreview(ctx echo.Context) error {
	req := new(PreviewRequest)
	if err := ctx.Bind(req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid JSON"})
	}

	// Validate URL format and scheme
	parsedURL, err := url.Parse(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid URL format"})
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Only HTTP/HTTPS URLs are allowed"})
	}

	// Create HTTP client with SSRF protection
	transport := &http.Transport{
		DialContext: customDialContext,
	}
	client := &http.Client{
		Timeout: 3 * time.Second,
		Transport: transport,
		CheckRedirect: func(req *http.Request, via []*http.Request) error {
			if len(via) >= 10 {
				return errors.New("too many redirects")
			}
			// Ensure redirect URLs are also HTTP/HTTPS
			if req.URL.Scheme != "http" && req.URL.Scheme != "https" {
				return errors.New("redirect to non-HTTP/HTTPS URL")
			}
			return nil
		},
	}

	// Create HTTP request with context from the Echo handler
	httpReq, err := http.NewRequestWithContext(ctx.Request().Context(), http.MethodGet, parsedURL.String(), nil)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to create request"})
	}
	httpReq.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreviewBot/1.0)")

	// Execute the request
	resp, err := client.Do(httpReq)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to fetch URL"})
	}
	defer resp.Body.Close()

	// Check HTTP status code
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": fmt.Sprintf("HTTP %d", resp.StatusCode)})
	}

	// Check Content-Type is HTML
	contentType := resp.Header.Get("Content-Type")
	if !strings.HasPrefix(contentType, "text/html") && !strings.HasPrefix(contentType, "application/xhtml+xml") {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "URL does not return HTML content"})
	}

	// Read response body with size limit to prevent OOM
	const maxBodySize = 1 << 20 // 1 MB
	body, err := io.ReadAll(io.LimitReader(resp.Body, maxBodySize))
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to read response body"})
	}

	// Extract title and description from HTML
	title, description := extractTitleAndDescription(body)

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

func extractTitleAndDescription(htmlContent []byte) (string, string) {
	var title string
	var description string

	// Parse HTML content
	doc, err := html.Parse(bytes.NewReader(htmlContent))
	if err != nil {
		return "", ""
	}

	// Traverse the HTML node tree
	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if n.Type == html.ElementNode {
			switch n.Data {
			case "title":
				// Extract text content from title tag
				var textBuilder strings.Builder
				for child := n.FirstChild; child != nil; child = child.NextSibling {
					if child.Type == html.TextNode {
						textBuilder.WriteString(child.Data)
					}
				}
				title = strings.TrimSpace(textBuilder.String())
			case "meta":
				// Check for description meta tag
				var nameAttr, contentAttr string
				for _, attr := range n.Attr {
					switch strings.ToLower(attr.Key) {
					case "name":
						nameAttr = attr.Val
					case "content":
						contentAttr = attr.Val
					}
				}
				if strings.EqualFold(nameAttr, "description") {
					description = strings.TrimSpace(contentAttr)
				}
			}
		}

		// Recursively traverse child nodes
		for child := n.FirstChild; child != nil; child = child.NextSibling {
			traverse(child)
		}
	}

	traverse(doc)

	return title, description
}

func main() {
	e := echo.New()
	e.POST("/preview", FetchURLPreview)
	e.Start(":8080")
}

