package main

import (
	"io"
	"net/http"
	"strings"
	"time"

	"github.com/labstack/echo/v4"
	"golang.org/x/net/html"
)

// PreviewRequest represents the incoming request with URL
type PreviewRequest struct {
	URL string `json:"url"`
}

// PreviewResponse represents the outgoing response with title and description
type PreviewResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
}

// extractPreview parses HTML content to extract page title and meta description
func extractPreview(r io.Reader) (string, string, error) {
	doc, err := html.Parse(r)
	if err != nil {
		return "", "", err
	}

	var title string
	var description string

	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if n.Type == html.ElementNode {
			switch n.Data {
			case "title":
				// Extract text from title tag
				if n.FirstChild != nil && n.FirstChild.Type == html.TextNode {
					title = strings.TrimSpace(n.FirstChild.Data)
				}
			case "meta":
				// Check for description meta tag (case-insensitive name match)
				var name, content string
				for _, attr := range n.Attr {
					switch attr.Key {
					case "name":
						name = attr.Val
					case "content":
						content = attr.Val
					}
				}
				if strings.EqualFold(name, "description") {
					description = strings.TrimSpace(content)
				}
			}
		}
		// Recursively traverse child nodes
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}

	traverse(doc)
	return title, description, nil
}

// FetchURLPreview handles POST requests to /preview to fetch and parse URL content
func FetchURLPreview(ctx echo.Context) error {
	var req PreviewRequest
	if err := ctx.Bind(&req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "invalid request body"})
	}

	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "url is required"})
	}

	// Create HTTP client with 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Fetch the URL content
	resp, err := client.Get(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "failed to fetch URL: " + err.Error()})
	}
	defer resp.Body.Close()

	// Extract title and description from HTML
	title, description, err := extractPreview(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "failed to parse HTML: " + err.Error()})
	}

	// Return successful response
	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

func main() {
	// Initialize Echo instance
	e := echo.New()

	// Register handler for POST /preview
	e.POST("/preview", FetchURLPreview)

	// Start server on port 8080
	e.Logger.Fatal(e.Start(":8080"))
}

