	Description string `json:"description"`
}

type ErrorResponse struct {
	Error string `json:"error"`
}

func FetchURLPreview(ctx echo.Context) error {
	var req PreviewRequest
	if err := ctx.Bind(&req); err!= nil {
		return ctx.JSON(http.StatusBadRequest, ErrorResponse{Error: "Invalid request body"})
	}

	req.URL = strings.TrimSpace(req.URL)
	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, ErrorResponse{Error: "URL is required"})
	}

	parsedURL, err := url.Parse(req.URL)
	if err!= nil {
		return ctx.JSON(http.StatusBadRequest, ErrorResponse{Error: "Invalid URL format"})
	}
	if parsedURL.Scheme!= "http" && parsedURL.Scheme!= "https" {
		return ctx.JSON(http.StatusBadRequest, ErrorResponse{Error: "URL must use http or https scheme"})
	}

	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	reqHTTP, err := http.NewRequestWithContext(ctx.Request().Context(), http.MethodGet, req.URL, nil)
	if err!= nil {
		return ctx.JSON(http.StatusInternalServerError, ErrorResponse{Error: "Failed to create request"})
	}
	reqHTTP.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreviewBot/1.0; +https://example.com)")

	resp, err := client.Do(reqHTTP)
	if err!= nil {
		return ctx.JSON(http.StatusBadGateway, ErrorResponse{Error: "Failed to fetch URL: " + err.Error()})
	}
	defer resp.Body.Close()

	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.JSON(http.StatusBadGateway, ErrorResponse{Error: "URL returned non-success status: " + resp.Status})
	}

	contentType := resp.Header.Get("Content-Type")
	if!strings.HasPrefix(strings.ToLower(contentType), "text/html") {
		return ctx.JSON(http.StatusUnsupportedMediaType, ErrorResponse{Error: "Content is not HTML"})
	}

	doc, err := goquery.NewDocumentFromReader(resp.Body)
	if err!= nil {
		return ctx.JSON(http.StatusInternalServerError, ErrorResponse{Error: "Failed to parse HTML"})
	}

	title := strings.TrimSpace(doc.Find("title").First().Text())
	description, _ := doc.Find("meta[name=\"description\"]").First().Attr("content")
	description = strings.TrimSpace(description)

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

