	"net/http"
	"net/url"
	"strings"
	"time"

	"github.com/labstack/echo/v4"
	"golang.org/x/net/html"
)

// Request body
type PreviewRequest struct {
	URL string `json:"url"`
}

// Response body
type PreviewResponse struct {
	Title       string `json:"title,omitempty"`
	Description string `json:"description,omitempty"`
}

var blockedNetworks = []*net.IPNet{
	// Loopback addresses
	{IP: net.ParseIP("127.0.0.0"), Mask: net.CIDRMask(8, 32)},
	{IP: net.ParseIP("::1"), Mask: net.CIDRMask(128, 128)},
	// Private networks
	{IP: net.ParseIP("10.0.0.0"), Mask: net.CIDRMask(8, 32)},
	{IP: net.ParseIP("172.16.0.0"), Mask: net.CIDRMask(12, 32)},
	{IP: net.ParseIP("192.168.0.0"), Mask: net.CIDRMask(16, 32)},
	// Link-local addresses
	{IP: net.ParseIP("169.254.0.0"), Mask: net.CIDRMask(16, 32)},
	{IP: net.ParseIP("fe80::"), Mask: net.CIDRMask(10, 128)},
	// Wildcard address
	{IP: net.ParseIP("0.0.0.0"), Mask: net.CIDRMask(32, 32)},
}

func isBlockedIP(ip net.IP) bool {
	// Handle IPv4-mapped IPv6 addresses by converting to IPv4
	if ipv4 := ip.To4(); ipv4 != nil {
		ip = ipv4
	}
	for _, network := range blockedNetworks {
		if network.Contains(ip) {
			return true
		}
	}
	return false
}

func validateURL(ctx context.Context, u *url.URL) ([]net.IP, error) {
	// Validate scheme
	if u.Scheme != "http" && u.Scheme != "https" {
		return nil, errors.New("only HTTP/HTTPS URLs are allowed")
	}

	// Resolve hostname to IP addresses
	ips, err := net.DefaultResolver.LookupIP(ctx, "ip", u.Hostname())
	if err != nil {
		return nil, fmt.Errorf("failed to resolve hostname: %w", err)
	}

	// Filter out blocked IPs
	var validIPs []net.IP
	for _, ip := range ips {
		if !isBlockedIP(ip) {
			validIPs = append(validIPs, ip)
		}
	}

	if len(validIPs) == 0 {
		return nil, errors.New("URL resolves to blocked IP address")
	}

	return validIPs, nil
}

// SSRFProtectedRoundTripper is a custom RoundTripper that protects against SSRF attacks
type SSRFProtectedRoundTripper struct{}

func NewSSRFProtectedRoundTripper() *SSRFProtectedRoundTripper {
	return &SSRFProtectedRoundTripper{}
}

func (rt *SSRFProtectedRoundTripper) RoundTrip(req *http.Request) (*http.Response, error) {
	// Validate the request URL
	validIPs, err := validateURL(req.Context(), req.URL)
	if err != nil {
		return nil, err
	}

	// Select the first valid IP
	targetIP := validIPs[0]

	// Determine the port
	port := req.URL.Port()
	if port == "" {
		if req.URL.Scheme == "https" {
			port = "443"
		} else {
			port = "80"
		}
	}
	addr := net.JoinHostPort(targetIP.String(), port)

	// Create a transport with custom DialContext to use the validated IP
	transport := &http.Transport{
		DialContext: func(ctx context.Context, network, _ string) (net.Conn, error) {
			return (&net.Dialer{}).DialContext(ctx, network, addr)
		},
	}

	// Ensure the Host header is set correctly to the original hostname
	req.Host = req.URL.Host

	// Perform the request
	return transport.RoundTrip(req)
}

func FetchURLPreview(ctx echo.Context) error {
	previewReq := new(PreviewRequest)
	if err := ctx.Bind(previewReq); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid JSON"})
	}

	// Parse and validate the URL
	parsedURL, err := url.Parse(previewReq.URL)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid URL format"})
	}

	// Create HTTP request
	httpReq, err := http.NewRequestWithContext(ctx.Request().Context(), http.MethodGet, parsedURL.String(), nil)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to create HTTP request"})
	}
	httpReq.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreviewBot/1.0)")

	// Create HTTP client with SSRF protection
	client := &http.Client{
		Timeout: 3 * time.Second,
		Transport: NewSSRFProtectedRoundTripper(),
		CheckRedirect: func(req *http.Request, via []*http.Request) error {
			if len(via) >= 10 {
				return errors.New("too many redirects")
			}
			return nil
		},
	}

	// Fetch the URL
	resp, err := client.Do(httpReq)
	if err != nil {
		// Return 400 for validation errors, 500 for others
		if strings.Contains(err.Error(), "only HTTP/HTTPS") || 
		   strings.Contains(err.Error(), "blocked IP") || 
		   strings.Contains(err.Error(), "failed to resolve hostname") {
			return ctx.JSON(http.StatusBadRequest, map[string]string{"error": err.Error()})
		}
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to fetch URL"})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": fmt.Sprintf("HTTP %d", resp.StatusCode)})
	}

	body, err := io.ReadAll(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to read response body"})
	}

	title, description := extractTitleAndDescription(body)

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

func extractTitleAndDescription(htmlContent []byte) (string, string) {
	var title string
	var description string

	doc, err := html.Parse(bytes.NewReader(htmlContent))
	if err != nil {
		return "", ""
	}

	// Helper function to extract all text content from a node
	getTextContent := func(n *html.Node) string {
		var buf bytes.Buffer
		var traverse func(*html.Node)
		traverse = func(c *html.Node) {
			if c.Type == html.TextNode {
				buf.WriteString(c.Data)
			}
			for child := c.FirstChild; child != nil; child = child.NextSibling {
				traverse(child)
			}
		}
		traverse(n)
		return strings.TrimSpace(buf.String())
	}

	// Traverse the HTML tree to find title and meta description
	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if n.Type == html.ElementNode {
			switch strings.ToLower(n.Data) {
			case "title":
				title = getTextContent(n)
			case "meta":
				var nameAttr, contentAttr string
				for _, attr := range n.Attr {
					switch strings.ToLower(attr.Key) {
					case "name":
						nameAttr = strings.ToLower(attr.Val)
					case "content":
						contentAttr = attr.Val
					}
				}
				if nameAttr == "description" {
					description = strings.TrimSpace(contentAttr)
				}
			}
		}
		// Recursively check child nodes
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}
	traverse(doc)

	return title, description
}

func main() {
	e := echo.New()
	// Register the handler under /preview path as required
	e.POST("/preview", FetchURLPreview)
	// Start the server on port 8080
	e.Logger.Fatal(e.Start(":8080"))
}

