import (
	"bytes"
	"context"
	"fmt"
	"io"
	"net"
	"net/http"
	"net/url"
	"strings"
	"time"

	"github.com/labstack/echo/v4"
	"golang.org/x/net/html"
)

// Request body
type PreviewRequest struct {
	URL string `json:"url"`
}

// Response body
type PreviewResponse struct {
	Title       string `json:"title,omitempty"`
	Description string `json:"description,omitempty"`
}

const maxBodySize = 1 << 20 // 1 MB maximum HTML body to parse

var safeDialer = &net.Dialer{
	Timeout:   3 * time.Second,
	KeepAlive: 30 * time.Second,
}

func safeDialContext(ctx context.Context, network, addr string) (net.Conn, error) {
	// Split host and port from the address
	host, _, err := net.SplitHostPort(addr)
	if err!= nil {
		return nil, fmt.Errorf("invalid address: %w", err)
	}

	// Resolve host to IP addresses using the context
	ips, err := net.DefaultResolver.LookupIP(ctx, "ip", host)
	if err!= nil {
		return nil, fmt.Errorf("failed to resolve host: %w", err)
	}

	// Validate each resolved IP
	for _, ip := range ips {
		if ip.IsLoopback() {
			return nil, fmt.Errorf("loopback addresses are not allowed")
		}
		if ip.IsPrivate() {
			return nil, fmt.Errorf("private IP addresses are not allowed")
		}
		if ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
			return nil, fmt.Errorf("link-local addresses are not allowed")
		}
	}

	// Proceed with dialing the address
	return safeDialer.DialContext(ctx, network, addr)
}

func FetchURLPreview(ctx echo.Context) error {
	req := new(PreviewRequest)
	if err := ctx.Bind(req); err!= nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid JSON"})
	}

	// Validate URL format and scheme
	parsedURL, err := url.Parse(req.URL)
	if err!= nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid URL format"})
	}

	if parsedURL.Scheme!= "http" && parsedURL.Scheme!= "https" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Only HTTP/HTTPS URLs are allowed"})
	}

	// Create HTTP client with safe transport to prevent SSRF
	client := &http.Client{
		Timeout: 3 * time.Second,
		Transport: &http.Transport{
			DialContext: safeDialContext,
		},
	}

	// Create HTTP request with the echo context for cancellation
	httpReq, err := http.NewRequestWithContext(ctx.Request().Context(), http.MethodGet, parsedURL.String(), nil)
	if err!= nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to create request"})
	}
	httpReq.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreviewBot/1.0)")

	// Execute the request
	resp, err := client.Do(httpReq)
	if err!= nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Failed to fetch URL"})
	}
	defer resp.Body.Close()

	// Check for successful status code
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": fmt.Sprintf("HTTP error: %d", resp.StatusCode)})
	}

	// Validate Content-Type is HTML
	contentType := resp.Header.Get("Content-Type")
	if!strings.HasPrefix(strings.ToLower(contentType), "text/html") {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "URL does not return HTML content"})
	}

