package main

import (
	"context"
	"errors"
	"fmt"
	"io"
	"net"
	"net/http"
	"net/url"
	"strings"
	"time"

	"github.com/labstack/echo/v4"
	"golang.org/x/net/html"
)

// Request body
type PreviewRequest struct {
	URL string `json:"url"`
}

// Response body
type PreviewResponse struct {
	Title       string `json:"title,omitempty"`
	Description string `json:"description,omitempty"`
}

var (
	errPrivateIP = errors.New("private IP address not allowed")
)

const (
	maxBodySize    = 1 << 20 // 1 MB
	defaultTimeout = 3 * time.Second
	userAgent      = "Mozilla/5.0 (compatible; URLPreviewBot/1.0)"
)

func isPrivateIP(ip net.IP) bool {
	if ip == nil {
		return true
	}
	// Check loopback, link-local addresses
	if ip.IsLoopback() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
		return true
	}
	// Private IPv4 ranges
	privateIPv4Blocks := []*net.IPNet{
		{IP: net.ParseIP("10.0.0.0"), Mask: net.CIDRMask(8, 32)},
		{IP: net.ParseIP("172.16.0.0"), Mask: net.CIDRMask(12, 32)},
		{IP: net.ParseIP("192.168.0.0"), Mask: net.CIDRMask(16, 32)},
	}
	for _, block := range privateIPv4Blocks {
		if block.Contains(ip) {
			return true
		}
	}
	// IPv6 unique local address (ULA)
	privateIPv6Block := &net.IPNet{IP: net.ParseIP("fc00::"), Mask: net.CIDRMask(7, 128)}
	return privateIPv6Block.Contains(ip)
}

func customDialContext(ctx context.Context, network, addr string) (net.Conn, error) {
	dialer := &net.Dialer{}
	conn, err := dialer.DialContext(ctx, network, addr)
	if err != nil {
		return nil, err
	}
	// Verify the remote IP address after connecting
	tcpAddr, ok := conn.RemoteAddr().(*net.TCPAddr)
	if !ok {
		conn.Close()
		return nil, errors.New("unsupported address type")
	}
	if isPrivateIP(tcpAddr.IP) {
		conn.Close()
		return nil, errPrivateIP
	}
	return conn, nil
}

func extractTitleAndDescription(htmlContent []byte) (string, string) {
	var title string
	var description string
	reader := strings.NewReader(string(htmlContent))
	tokenizer := html.NewTokenizer(reader)
	inTitle := false

	for {
		tokenType := tokenizer.Next()
		switch tokenType {
		case html.ErrorToken:
			// Exit on end of document or error
			return title, description
		case html.StartTagToken:
			tagName, hasAttr := tokenizer.TagName()
			switch strings.ToLower(string(tagName)) {
			case "title":
				inTitle = true
			case "meta":
				var nameAttr string
				var contentAttr string
				for hasAttr {
					attrKey, attrVal, moreAttr := tokenizer.TagAttr()
					switch strings.ToLower(string(attrKey)) {
					case "name":
						nameAttr = strings.ToLower(string(attrVal))
					case "content":
						contentAttr = string(attrVal)
					}
					hasAttr = moreAttr
				}
				if nameAttr == "description" {
					description = contentAttr
				}
			}
		case html.TextToken:
			if inTitle {
				title = strings.TrimSpace(string(tokenizer.Text()))
			}
		case html.EndTagToken:
			tagName, _ := tokenizer.TagName()
			switch strings.ToLower(string(tagName)) {
			case "title":
				inTitle = false
			case "head":
