func FetchURLPreview(ctx echo.Context) error {
	previewReq := new(PreviewRequest)
	if err := ctx.Bind(previewReq); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid JSON"})
	}

	// Validate URL format and scheme
	parsedURL, err := url.Parse(previewReq.URL)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid URL format"})
	}
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Only HTTP/HTTPS URLs are allowed"})
	}

	// Configure HTTP client with SSRF protection and timeout
	transport := &http.Transport{
		DialContext: customDialContext,
	}
	client := &http.Client{
		Timeout:   defaultTimeout,
		Transport: transport,
	}

	// Create HTTP request with context from the echo request
	httpReq, err := http.NewRequestWithContext(ctx.Request().Context(), http.MethodGet, "", nil)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to create request"})
	}
	httpReq.URL = parsedURL
	httpReq.Header.Set("User-Agent", userAgent)

	// Execute the request
	resp, err := client.Do(httpReq)
	if err != nil {
		if errors.Is(err, errPrivateIP) {
			return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "URL resolves to a private IP address, which is not allowed"})
		}
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to fetch URL"})
	}
	defer resp.Body.Close()

	// Check for successful HTTP status
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": fmt.Sprintf("HTTP error: %d", resp.StatusCode)})
	}

	// Validate that the response is HTML
	contentType := resp.Header.Get("Content-Type")
	if !strings.HasPrefix(strings.ToLower(contentType), "text/html") && !strings.HasPrefix(strings.ToLower(contentType), "application/xhtml+xml") {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "URL does not return HTML content"})
	}

	// Read response body with a size limit to prevent memory exhaustion
	body, err := io.ReadAll(io.LimitReader(resp.Body, maxBodySize))
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to read response body"})
	}

	// Extract title and description from HTML
	title, description := extractTitleAndDescription(body)

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

func main() {
	e := echo.New()
	e.POST("/preview", FetchURLPreview)
	// Start server on port 8080
	e.Start(":8080")
}

