package main

import (
	"net/http"
	"strings"
	"time"

	"github.com/PuerkitoBio/goquery"
	"github.com/labstack/echo/v4"
)

// PreviewRequest represents the incoming JSON request body
type PreviewRequest struct {
	URL string `json:"url"`
}

// PreviewResponse represents the outgoing JSON response
type PreviewResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
}

// FetchURLPreview handles POST requests to /preview, fetches and parses the URL
func FetchURLPreview(ctx echo.Context) error {
	var req PreviewRequest
	if err := ctx.Bind(&req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "invalid request body"})
	}

	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "url field is required"})
	}

	// Create HTTP client with 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Fetch the URL
	resp, err := client.Get(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "failed to fetch URL: " + err.Error()})
	}
	defer resp.Body.Close()

	// Check for successful response
	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "unexpected HTTP status: " + resp.Status})
	}

	// Verify content type is HTML
	contentType := resp.Header.Get("Content-Type")
	if !strings.HasPrefix(strings.ToLower(contentType), "text/html") {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "URL does not return HTML content"})
	}

	// Parse HTML document
	doc, err := goquery.NewDocumentFromReader(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "failed to parse HTML content"})
	}

	// Extract and clean page title
	title := strings.TrimSpace(doc.Find("title").Text())

	// Extract and clean meta description
	description, _ := doc.Find("meta[name='description']").Attr("content")
	description = strings.TrimSpace(description)

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

func main() {
	e := echo.New()
	e.POST("/preview", FetchURLPreview)
	// Start server on port 8080
	e.Start(":8080")
}

