// PreviewRequest represents the incoming JSON request with URL
type PreviewRequest struct {
	URL string `json:"url"`
}

// PreviewResponse represents the outgoing JSON response with title and description
type PreviewResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
}

// HTTP client with 3-second timeout as required
var httpClient = &http.Client{
	Timeout: 3 * time.Second,
}

// FetchURLPreview is the echo handler to fetch and parse URL preview
func FetchURLPreview(ctx echo.Context) error {
	var req PreviewRequest
	if err := ctx.Bind(&req); err!= nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{
			"error": "invalid request body format",
		})
	}

	req.URL = strings.TrimSpace(req.URL)
	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{
			"error": "url field is required",
		})
	}

	parsedURL, err := url.Parse(req.URL)
	if err!= nil || (parsedURL.Scheme!= "http" && parsedURL.Scheme!= "https") {
		return ctx.JSON(http.StatusBadRequest, map[string]string{
			"error": "invalid url: must be a valid http/https url",
		})
	}

	resp, err := httpClient.Get(req.URL)
	if err!= nil {
		return ctx.JSON(http.StatusBadGateway, map[string]string{
			"error": fmt.Sprintf("failed to fetch url: %v", err),
		})
	}
	defer resp.Body.Close()

	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.JSON(http.StatusBadGateway, map[string]string{
			"error": fmt.Sprintf("upstream server returned status %d", resp.StatusCode),
		})
	}

