	if!strings.HasPrefix(strings.ToLower(contentType), "text/html") {
		return ctx.JSON(http.StatusBadRequest, map[string]string{
			"error": "url does not return an HTML document",
		})
	}

	title, description, err := parseHTML(resp.Body)
	if err!= nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{
			"error": "failed to parse HTML content",
		})
	}

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

// parseHTML extracts title and meta description from HTML reader
func parseHTML(r io.Reader) (string, string, error) {
	tokenizer := html.NewTokenizer(r)
	var titleBuilder strings.Builder
	var description string
	inTitle := false

	for {
		tokenType := tokenizer.Next()
		switch tokenType {
		case html.ErrorToken:
			err := tokenizer.Err()
			if err == io.EOF {
				return strings.TrimSpace(titleBuilder.String()), strings.TrimSpace(description), nil
			}
			return "", "", err

		case html.StartTagToken, html.SelfClosingTagToken:
			tagName, hasAttr := tokenizer.TagName()
			tagNameStr := strings.ToLower(string(tagName))

			switch tagNameStr {
			case "title":
