			case "meta":
				if hasAttr {
					var nameAttr string
					var contentAttr string
					for {
						attrKey, attrVal, moreAttr := tokenizer.TagAttr()
						keyLower := strings.ToLower(string(attrKey))
						switch keyLower {
						case "name":
