type previewRequest struct {
	URL string `json:"url"`
}

type previewResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
}

func getTextContent(n *html.Node) string {
	var buf strings.Builder
	var collect func(*html.Node)
	collect = func(c *html.Node) {
		if c.Type == html.TextNode {
			buf.WriteString(c.Data)
		}
		for child := c.FirstChild; child!= nil; child = child.NextSibling {
			collect(child)
		}
	}
	collect(n)
	return strings.TrimSpace(buf.String())
}

func extractMetadata(r io.Reader) (title, description string, err error) {
	doc, err := html.Parse(r)
	if err!= nil {
		return "", "", err
	}

	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if n.Type == html.ElementNode {
			switch n.Data {
			case "title":
				title = getTextContent(n)
			case "meta":
				var nameAttr, contentAttr string
				for _, a := range n.Attr {
					switch strings.ToLower(a.Key) {
					case "name":
						nameAttr = strings.ToLower(a.Val)
					case "content":
						contentAttr = a.Val
					}
				}
				if nameAttr == "description" {
					description = strings.TrimSpace(contentAttr)
				}
			}
		}
		for child := n.FirstChild; child!= nil; child = child.NextSibling {
			traverse(child)
		}
	}
	traverse(doc)
	return title, description, nil
}

func FetchURLPreview(ctx echo.Context) error {
	var req previewRequest
	if err := ctx.Bind(&req); err!= nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "invalid request body"})
	}

	req.URL = strings.TrimSpace(req.URL)
	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "url is required"})
	}

	parsedURL, err := url.Parse(req.URL)
	if err!= nil || (parsedURL.Scheme!= "http" && parsedURL.Scheme!= "https") {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "invalid URL, must use http or https scheme"})
	}

	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	httpReq, err := http.NewRequestWithContext(ctx.Request().Context(), http.MethodGet, req.URL, nil)
	if err!= nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "failed to create HTTP request"})
	}
	httpReq.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreviewBot/1.0; +https://example.com)")

	resp, err := client.Do(httpReq)
	if err!= nil {
		return ctx.JSON(http.StatusBadGateway, map[string]string{"error": fmt.Sprintf("failed to fetch URL: %v", err)})
	}
	defer resp.Body.Close()

	if resp.StatusCode!= http.StatusOK {
		return ctx.JSON(http.StatusBadGateway, map[string]string{"error": fmt.Sprintf("URL returned non-OK status: %d", resp.StatusCode)})
	}

	contentType := resp.Header.Get("Content-Type")
	if contentType!= "" {
		mediaType, _, err := mime.ParseMediaType(contentType)
		if err == nil && mediaType!= "text/html" && mediaType!= "application/xhtml+xml" {
