		}
	}

	title, description, err := extractMetadata(resp.Body)
	if err!= nil {
		return ctx.JSON(http.StatusUnprocessableEntity, map[string]string{"error": "failed to parse HTML content"})
	}

	return ctx.JSON(http.StatusOK, previewResponse{
		Title:       title,
		Description: description,
	})
}

