// PreviewRequest represents the incoming request body with the URL to preview
type PreviewRequest struct {
	URL string `json:"url"`
}

// PreviewResponse represents the outgoing response with title and description
type PreviewResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
}

// extractPreview parses HTML from an io.Reader and extracts the page title and meta description
func extractPreview(r io.Reader) (string, string, error) {
	doc, err := html.Parse(r)
	if err != nil {
		return "", "", fmt.Errorf("failed to parse HTML: %w", err)
	}

	var title string
	var description string

	var walk func(*html.Node)
	walk = func(n *html.Node) {
		if n.Type == html.ElementNode {
			switch strings.ToLower(n.Data) {
			case "title":
				// Collect all text content inside the title tag
				var titleText strings.Builder
				for child := n.FirstChild; child != nil; child = child.NextSibling {
					if child.Type == html.TextNode {
						titleText.WriteString(child.Data)
					}
				}
				title = strings.TrimSpace(titleText.String())
			case "meta":
				// Check for meta description tag (case-insensitive attributes)
				metaName := ""
				metaContent := ""
				for _, attr := range n.Attr {
					switch strings.ToLower(attr.Key) {
					case "name":
						metaName = strings.ToLower(attr.Val)
					case "content":
						metaContent = attr.Val
					}
				}
				if metaName == "description" {
					description = strings.TrimSpace(metaContent)
				}
			}
		}
		// Recursively walk through child nodes
		for child := n.FirstChild; child != nil; child = child.NextSibling {
			walk(child)
		}
	}

	walk(doc)
	return title, description, nil
}

// FetchURLPreview is the Echo handler for URL preview requests
func FetchURLPreview(ctx echo.Context) error {
	var req PreviewRequest
	// Bind the incoming JSON request to the PreviewRequest struct
	if err := ctx.Bind(&req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{
			"error": "Invalid request body: " + err.Error(),
		})
	}

	// Validate that the URL is provided
	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{
			"error": "URL field is required",
		})
	}

	// Create an HTTP client with a 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Fetch the content from the provided URL
	resp, err := client.Get(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{
			"error": fmt.Sprintf("Failed to fetch URL: %v", err),
		})
	}
	// Ensure the response body is closed when we're done
	defer resp.Body.Close()

	// Check if the HTTP response status is successful (2xx)
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{
			"error": fmt.Sprintf("URL returned non-success status: %s", resp.Status),
		})
	}

	// Extract title and description from the HTML response
	title, description, err := extractPreview(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{
			"error": err.Error(),
		})
	}

	// Return the successful preview response
	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

func main() {
	// Create a new Echo instance
	e := echo.New()

	// Register the FetchURLPreview handler at the /preview path for POST requests
	e.POST("/preview", FetchURLPreview)

	// Start the server on port 8080
	e.Logger.Fatal(e.Start(":8080"))
}

